set -euo pipefail

cd "$(dirname "$0")/.."   # cd to repo root

# --- Step 1: prerequisites ---
command -v uv >/dev/null 2>&1 || { echo "[setup_uv] uv not found — install via 'curl -fsSL https://astral.sh/uv/install.sh | sh'" >&2; exit 1; }

# --- Step 2: create venv (idempotent) ---
if [ ! -d .venv ]; then
  uv venv --python 3.12 .venv
else
  echo "[setup_uv] .venv already exists; reusing"
fi

# Activate venv for the rest of this script.
# shellcheck disable=SC1091
source .venv/bin/activate

