# Video writer used by benchmark-generator render_random.py (and rl render.py).
uv pip install 'imageio[ffmpeg]'
# Plotting used by rl train.py end-of-training learning-curve dump.
uv pip install matplotlib
# Hydra / OmegaConf used by all rl-integration-generator scripts (train/eval/render).
uv pip install hydra-core omegaconf
